nta.declaration:
// Industrial Policy Monitor scenario.
// This specific-layer model composes selected Registration profiles:
// Bootstrap-to-Registration binding, endpoint identity binding, cloned-device
// rejection, and Deregister/offline cleanup. The PolicyMonitor automaton
// converts protocol/profile evidence into industrial predicates.

const int MAX_CLIENTS = 2;
const int ENDPOINT_COUNT = 1;
typedef int[0, MAX_CLIENTS-1] client_id_t;
typedef int[0, ENDPOINT_COUNT-1] endpoint_id_t;

const int CLIENT_STATE_BOOTSTRAP_COMPLETE = 1;
const int CLIENT_STATE_REGISTERING = 2;
const int CLIENT_STATE_REGISTERED = 3;
const int CLIENT_STATE_REJECTED = 4;
const int CLIENT_STATE_DEREGISTERING = 5;
const int CLIENT_STATE_DEREGISTERED = 6;
const int CLIENT_STATE_OFFLINE = 7;

const int AUTHORIZED_SERVER_ID = 10;
const int BOOTSTRAPPED_CREDENTIAL = 700;
const int DUPLICATE_ENDPOINT_ID = 0;
const int OWNER_NONE = 0;
const int OWNER_CLIENT0 = 1;
const int OWNER_CLIENT1 = 2;
const int LEGIT_SECRET = 321;
const int CLONE_SECRET = 999;

const bool BINDING_ENABLED = true;
const bool IDENTITY_BINDING_ENABLED = true;
const bool DUPLICATE_ENDPOINT_DETECTION_ENABLED = true;
const bool CLEANUP_POLICY_ENABLED = true;

chan register_start[MAX_CLIENTS];
chan register_objects[MAX_CLIENTS];
chan register_ack[MAX_CLIENTS];
chan register_reject[MAX_CLIENTS];
chan deregister_start[MAX_CLIENTS];
chan deregister_ack[MAX_CLIENTS];

chan policy_admit[MAX_CLIENTS];
chan policy_clone_reject[MAX_CLIENTS];
chan policy_deregister_cleanup[MAX_CLIENTS];
chan policy_offline_cleanup[MAX_CLIENTS];

bool bootstrap_completed[MAX_CLIENTS];
bool object_list_received[MAX_CLIENTS];
bool client_registered[MAX_CLIENTS];
bool registration_rejected[MAX_CLIENTS];
bool registration_ack_received[MAX_CLIENTS];
bool deregister_requested[MAX_CLIENTS];
bool deregister_ack_received[MAX_CLIENTS];
bool device_offline[MAX_CLIENTS];
bool offline_cleanup_done[MAX_CLIENTS];
bool server_session_active[MAX_CLIENTS];

bool binding_verified[MAX_CLIENTS];
bool identity_binding_verified[MAX_CLIENTS];
bool duplicate_endpoint_detected = false;
bool identity_mismatch_detected = false;
bool cloned_device_detected = false;
bool attack_detected = false;

bool command_authorized[MAX_CLIENTS];
bool policy_admission_granted[MAX_CLIENTS];
bool cloned_device_rejected[MAX_CLIENTS];
bool cloned_device_alarm = false;
bool stale_session_cleaned[MAX_CLIENTS];
bool session_cleanup_done[MAX_CLIENTS];

int client_state[MAX_CLIENTS];
int client_message_id[MAX_CLIENTS];
int server_last_msg_id[MAX_CLIENTS];
int endpoint_id[MAX_CLIENTS];
int bootstrapped_server_id[MAX_CLIENTS];
int registration_server_id[MAX_CLIENTS];
int bootstrapped_credential[MAX_CLIENTS];
int registration_credential[MAX_CLIENTS];
int provisioned_identity_secret[MAX_CLIENTS];
int presented_identity_secret[MAX_CLIENTS];
int owner_code[MAX_CLIENTS];
int server_session_owner[ENDPOINT_COUNT];
int registration_turn = 0;
int current_client = 0;

nta.system:
Client0 = Client(0);
Client1 = Client(1);
RegistrationServer0 = RegistrationServer();
PolicyMonitor0 = PolicyMonitor();

system Client0, Client1, RegistrationServer0, PolicyMonitor0;
